const ScreenshotsCarousel = ({ screenshots, title }) => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const screenshotCount = Array.isArray(screenshots) ? screenshots.length : 0;
  const hasScreenshots = screenshotCount > 0;
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    setActiveIndex(0);
  }, [screenshotCount]);

  useEffect(() => {
    if (!hasScreenshots || screenshotCount <= 1 || isPaused || prefersReducedMotion) {
      return undefined;
    }

    const interval = setInterval(() => {
      setActiveIndex(prev => (prev === screenshotCount - 1 ? 0 : prev + 1));
    }, 1000);

    return () => clearInterval(interval);
  }, [hasScreenshots, isPaused, prefersReducedMotion, screenshotCount]);

  if (!hasScreenshots) {
    return null;
  }

  const currentShot = screenshots[activeIndex];
  const goPrev = () =>
    setActiveIndex(prev => (prev === 0 ? screenshotCount - 1 : prev - 1));
  const goNext = () =>
    setActiveIndex(prev => (prev === screenshotCount - 1 ? 0 : prev + 1));

  const onKeyDown = e => {
    if (e.key === 'ArrowLeft') {
      e.preventDefault();
      goPrev();
    }
    if (e.key === 'ArrowRight') {
      e.preventDefault();
      goNext();
    }
  };

  return (
    <StyledCarousel
      aria-label={`${title} screenshots`}
      onKeyDown={onKeyDown}
      tabIndex={0}
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
      onFocus={() => setIsPaused(true)}
      onBlur={() => setIsPaused(false)}>
      <h2 className="carousel-header">Screenshots</h2>
      <div className="carousel-frame">
        <img className="carousel-image" src={currentShot.src} alt={currentShot.alt} loading="lazy" />
        {screenshotCount > 1 && (
          <>
            <button type="button" className="carousel-nav prev" onClick={goPrev} aria-label="Previous screenshot">
              ‹
            </button>
            <button type="button" className="carousel-nav next" onClick={goNext} aria-label="Next screenshot">
              ›
            </button>
          </>
        )}
      </div>

      {currentShot.alt && <p className="carousel-caption">{currentShot.alt}</p>}

      {screenshotCount > 1 && (
        <ul className="carousel-dots" aria-label="Screenshot pagination">
          {screenshots.map((shot, i) => (
            <li key={shot.src}>
              <button
                type="button"
                className={`dot ${i === activeIndex ? 'active' : ''}`}
                onClick={() => setActiveIndex(i)}
                aria-label={`Go to screenshot ${i + 1}`}
                aria-current={i === activeIndex ? 'true' : 'false'}
              />
            </li>
          ))}
        </ul>
      )}
    </StyledCarousel>
  );
};

ScreenshotsCarousel.propTypes = {
  screenshots: PropTypes.arrayOf(
    PropTypes.shape({
      src: PropTypes.string.isRequired,
      alt: PropTypes.string,
    }),
  ),
  title: PropTypes.string.isRequired,
};

ScreenshotsCarousel.defaultProps = {
  screenshots: [],
};

const WorkTemplate = ({ data, location }) => {
  const { frontmatter, html } = data.markdownRemark;
  const {
    title,
    company,
    role,
    timeline,
    summary,
    liveUrl,
    repositoryUrl,
    screenshots,
    architecture,
    roadmap,
    outcomes,
  } = frontmatter;

  return (
    <Layout location={location}>
      <Helmet title={`${title} Case Study`} />

      <StyledWorkContainer>
        <span className="breadcrumb">
          <span className="arrow">&larr;</span>
          <Link to="/#projects">Back to Work</Link>
        </span>

        <StyledWorkHeader>
          <p className="overline">Case Study</p>
          <h1 className="medium-heading">{title}</h1>
          {summary && <p className="summary">{summary}</p>}

          <StyledMeta>
            <div className="meta-card">
              <p className="meta-label">Company</p>
              <p className="meta-value">{company}</p>
            </div>
            <div className="meta-card">
              <p className="meta-label">Role</p>
              <p className="meta-value">{role}</p>
            </div>
            <div className="meta-card">
              <p className="meta-label">Timeline</p>
              <p className="meta-value">{timeline}</p>
            </div>
          </StyledMeta>

          <StyledActions>
            {liveUrl && (
              <a className="primary" href={liveUrl} target="_blank" rel="noreferrer">
                Visit Product
              </a>
            )}
            {repositoryUrl && (
              <a className="secondary" href={repositoryUrl} target="_blank" rel="noreferrer">
                View Repository
              </a>
            )}
          </StyledActions>
        </StyledWorkHeader>

        <ScreenshotsCarousel screenshots={screenshots} title={title} />

        <StyledInfoGrid>
          {architecture?.length > 0 && (
            <article className="info-card">
              <h2 className="info-title">Technical Architecture</h2>
              <ul className="info-list">
                {architecture.map((item, i) => (
                  <li key={i}>{item}</li>
                ))}
              </ul>
            </article>
          )}

          {roadmap?.length > 0 && (
            <article className="info-card">
              <h2 className="info-title">Delivery Roadmap</h2>
              <ul className="info-list">
                {roadmap.map((item, i) => (
                  <li key={i}>{item}</li>
                ))}
              </ul>
            </article>
          )}

          {outcomes?.length > 0 && (
            <article className="info-card">
              <h2 className="info-title">Outcomes</h2>
              <ul className="info-list">
                {outcomes.map((item, i) => (
                  <li key={i}>{item}</li>
                ))}
              </ul>
            </article>
          )}
        </StyledInfoGrid>

        <StyledWorkContent dangerouslySetInnerHTML={{ __html: html }} />
      </StyledWorkContainer>
    </Layout>
  );
};

WorkTemplate.propTypes = {
  data: PropTypes.object.isRequired,
  location: PropTypes.object.isRequired,
};

export default WorkTemplate;

